class SORTracker {
    Map<String, Integer> nameScoreMap;
    int count = 0;

    public SORTracker() {
        nameScoreMap = new HashMap<>();
    }

    public void add(String name, int score) {
        if (!nameScoreMap.containsKey(name)) {
            nameScoreMap.put(name, score);
            count++;
        }
    }

    public String get() {
        if (count == 0) {
            return null;
        }
        String result = nameScoreMap.values().stream()
            .max()
            .orElse(null);
        return result;
    }
}
```

